package com.example.singersgallery.service;

import com.example.singersgallery.beans.Singer;
import com.example.singersgallery.dao.IDao;
import java.util.ArrayList;
import java.util.List;

public class SingerService implements IDao<Singer> {
    private List<Singer> singers;
    private static SingerService instance;

    private SingerService() {
        singers = new ArrayList<>();
        seed();
    }

    public static SingerService getInstance() {
        if (instance == null) instance = new SingerService();
        return instance;
    }

    private void seed() {
        singers.add(new Singer("Beyoncé", "R&B / Pop", "data:image/jpeg;base64,", 5.0f));
        singers.add(new Singer("Michael Jackson", "Pop", "data:image/jpeg;base64,", 5.0f));
        singers.add(new Singer("Rihanna", "Pop / R&B", "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQmYsiuiihSRm4y9sSR-6VtqCBQNyi8mclzcQ&s", 4.8f));
        singers.add(new Singer("Adele", "Soul / Pop", "data:image/jpeg;base64,", 4.9f));
        singers.add(new Singer("Drake", "Hip-Hop / R&B", "data:image/jpeg;base64,", 4.7f));
        singers.add(new Singer("Taylor Swift", "Pop / Country", "data:image/jpeg;base64,", 4.8f));
        singers.add(new Singer("The Weeknd", "R&B / Pop", "data:image/jpeg;base64,", 4.7f));
        singers.add(new Singer("Eminem", "Hip-Hop / Rap", "data:image/jpeg;base64,", 4.9f));
        singers.add(new Singer("Ed Sheeran", "Pop / Folk", "data:image/jpeg;base64,", 4.6f));
        singers.add(new Singer("Shakira", "Pop / Latin", "data:image/jpeg;base64,", 4.7f));
        singers.add(new Singer("Justin Bieber", "Pop / R&B", "data:image/jpeg;base64,", 4.5f));
    }

    @Override public boolean create(Singer o) { return singers.add(o); }

    @Override public boolean update(Singer o) {
        for (Singer s : singers) {
            if (s.getId() == o.getId()) {
                s.setName(o.getName());
                s.setImg(o.getImg());
                s.setRating(o.getRating());
                return true;
            }
        }
        return false;
    }

    @Override public boolean delete(Singer o) { return singers.remove(o); }

    @Override public Singer findById(int id) {
        for (Singer s : singers) if (s.getId() == id) return s;
        return null;
    }

    @Override public List<Singer> findAll() { return singers; }
}